import React, { useState } from 'react';
import { Play, Square, Download, Users } from 'lucide-react';
import { jsPDF } from "jspdf";
import {font} from './THSarabunNew-normal.js';
import {bold} from './THSarabun Bold-bold.js'

const VotingControl = () => {
  const [isVotingOpen, setIsVotingOpen] = useState(false);

  // Mock Vote Data
  const candidates = [
    { id: 1, name: 'Somsri Wirat', category: 'Academic', approve: 8, reject: 2, totalCommittee: 12 },
    { id: 2, name: 'Kittipong J.', category: 'Activity', approve: 11, reject: 1, totalCommittee: 12 },
    { id: 3, name: 'Wichai K.', category: 'Innovation', approve: 5, reject: 5, totalCommittee: 12 }, // ยังไม่ผ่านครึ่ง
  ];

  const handleToggleVoting = () => {
    if(isVotingOpen) {
        if(window.confirm('Are you sure you want to CLOSE voting? This will calculate results.')) {
            setIsVotingOpen(false);
        }
    } else {
        setIsVotingOpen(true);
    }
  };
  const date = new Date();

    let day = date.getDate();
    let month = date.getMonth() + 1;
    let year = date.getFullYear() + 543;
    var currentDate;
    if (month == 1){currentDate = `${day}  มกราคม  ${year}`;}
    else if (month == 2){currentDate = `${day}  กุมภาพันธ์  ${year}`;}
    else if (month == 3){currentDate = `${day}  มีนาคม  ${year}`;}
    else if (month == 4){currentDate = `${day}  เมษายน  ${year}`;}
    else if (month == 5){currentDate = `${day}  พฤษภาคม  ${year}`;}
    else if (month == 6){currentDate = `${day}  มิถุนายน  ${year}`;}
    else if (month == 7){currentDate = `${day}  กรกฎาคม  ${year}`;}
    else if (month == 8){currentDate = `${day}  สิงหาคม  ${year}`;}
    else if (month == 9){currentDate = `${day}  กันยายน  ${year}`;}
    else if (month == 10){currentDate = `${day}  ตุลาคม  ${year}`;}
    else if (month == 11){currentDate = `${day}  พฤศจิกายน  ${year}`;}
    else if (month == 12){currentDate = `${day}  ธันวาคม  ${year}`;}
    

    const handleExportData = () =>{
        if(isVotingOpen) {
        if(window.confirm('Close the voting process first')) {
        }
    }
    else {
        const doc = new jsPDF();
        var pageWidth = doc.internal.pageSize.width || doc.internal.pageSize.getWidth();
        doc.addFileToVFS('THSarabunNew-normal.ttf', font);
        doc.addFont('THSarabunNew-normal.ttf', 'THSarabunNew', 'normal');
        doc.addFileToVFS('THSarabun Bold-bold.ttf', bold);
        doc.addFont('THSarabun Bold-bold.ttf', 'THSarabun Bold', 'bold');
        const ku_logo = "data:image/png;base64,"
        doc.addImage(ku_logo,"PNG",(pageWidth / 2) - 15, 15,30,30);
        doc.setFont('THSarabun Bold','bold')
        doc.text("ประกาศโครงการปริญญาตรี เรื่อง รายชื่อผู้ได้รับรางวัล นิสิตดีเด่น",pageWidth / 2,55,{align:"center"});
        doc.setFont('THSarabunNew','normal')
        doc.text("---------------------------------------------------------------------------",pageWidth / 2,63,{align:"center"});
        doc.setFont('THSarabun Bold','bold')
        doc.setFont('THSarabunNew','normal')
        var limit = 33
        var line = 4
        var academic = []
        var activaty = []
        var innovation = []
        var academicpasscount = 0
        var activatypasscount = 0
        var innovationpasscount = 0
        for (var printlist = 0;printlist < (candidates.length);printlist += 1){
            if(candidates[printlist].approve > (candidates[printlist].totalCommittee / 2))
                {if(candidates[printlist].category == 'Academic' ){
                    academicpasscount++;
                    academic.push(academicpasscount.toString()+"    "+ candidates[printlist].name + "    "  +candidates[printlist].id )
                } else if (candidates[printlist].category == 'Activity'){
                    activatypasscount++;
                    activaty.push(activatypasscount.toString()+"    "+ candidates[printlist].name + "    "  +candidates[printlist].id )
                }
                else if(candidates[printlist].category == 'Innovation'){
                    innovationpasscount++;
                    innovation.push(innovationpasscount.toString()+"    "+ candidates[printlist].name + "    " +candidates[printlist].id)
                }
            }
            
        }
        
        var print = []
        
        if(academic.length > 0){
            print.push('รายชื่อผู้ได้รับรางวัลด้านกิจกรรมเสริมหลักสูตร')
            for(var printlist = 0;printlist < (academic.length);printlist += 1){
            print.push(academic[printlist])
        }
        }
         if(activaty.length >0){
            print.push('รายชื่อผู้ได้รับรางวัลด้านความคิดสร้างสรรค์และนวัตกรรม')
        for(var printlist = 0;printlist < (activaty.length);printlist += 1){
            print.push(activaty[printlist])
        }
        }
         if(activaty.length >0){
            print.push('รายชื่อผู้ได้รับรางวัลด้านความประพฤติดี')
        for(var printlist = 0;printlist < (innovation.length);printlist += 1){
            print.push(innovation[printlist])
        }
        }
        doc.text(print ,pageWidth / 6,70)
        doc.text("ประกาศ ณ วันที่  " + currentDate,pageWidth * 0.75,250,{align:"center"});
        var chairman = []
        chairman.push('ประธานกรรมการดำเนินงาน')
        chairman.push('โครงการปริญญาตรี สาขาวิทยาการคอมพิวเตอร์ ภาคพิเศษ')
        doc.text("ประกาศ ณ วันที่  " + currentDate,pageWidth * 0.75,250,{align:"center"});
        doc.text(chairman,pageWidth * 0.75,270,{align:"center"});
        doc.save("a4.pdf");

    }
    };

  return (
    <div className="space-y-8">
      {/* Control Header */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex justify-between items-center">
        <div>
            <h1 className="text-2xl font-bold text-gray-800">Live Vote Control</h1>
            <p className="text-gray-500 flex items-center gap-2">
                Status: 
                <span className={`font-bold ${isVotingOpen ? 'text-green-600 animate-pulse' : 'text-red-500'}`}>
                    {isVotingOpen ? '● VOTING OPEN' : '● VOTING CLOSED'}
                </span>
            </p>
        </div>
        <div className="flex gap-3">
            <button onClick={handleExportData}
            className="flex items-center gap-2 px-4 py-2 border border-gray-300 rounded-lg bg-white hover:bg-gray-50 transition-all shadow-" >
                <Download size={18} /> Export Log
            </button>
            <button 
                onClick={handleToggleVoting}
                className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold text-white transition-all shadow-md
                ${isVotingOpen 
                    ? 'bg-red-500 hover:bg-red-600' 
                    : 'bg-green-600 hover:bg-green-700'}`}
            >
                {isVotingOpen ? <><Square size={18} fill="currentColor" /> Close Vote</> : <><Play size={18} /> Start Vote</>}
            </button>
        </div>
      </div>

      {/* Candidates Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {candidates.map((candidate) => {
            const approvePercent = (candidate.approve / candidate.totalCommittee) * 100;
            const isPassed = candidate.approve > (candidate.totalCommittee / 2);

            return (
                <div key={candidate.id} className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <h3 className="font-bold text-lg text-gray-800">{candidate.name}</h3>
                            <span className="text-xs bg-gray-100 px-2 py-1 rounded text-gray-600">{candidate.category}</span>
                        </div>
                        {isVotingOpen && <span className="text-xs text-green-600 font-bold animate-pulse">Live</span>}
                    </div>

                    {/* Progress Bar */}
                    <div className="space-y-2">
                        <div className="flex justify-between text-sm">
                            <span className="text-green-700 font-bold">{candidate.approve} Approve</span>
                            <span className="text-red-500 font-bold">{candidate.reject} Reject</span>
                        </div>
                        <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden flex">
                            <div 
                                className="h-full bg-ku-main transition-all duration-1000" 
                                style={{ width: `${approvePercent}%` }}
                            ></div>
                            <div 
                                className="h-full bg-red-400 transition-all duration-1000" 
                                style={{ width: `${(candidate.reject / candidate.totalCommittee) * 100}%` }}
                            ></div>
                        </div>
                        <p className="text-xs text-center text-gray-400 mt-1">
                            {candidate.approve + candidate.reject} / {candidate.totalCommittee} Voted
                        </p>
                    </div>

                    {/* Result Prediction */}
                    {!isVotingOpen && (
                        <div className={`mt-4 text-center py-2 rounded-lg text-sm font-bold border
                            ${isPassed 
                                ? 'bg-green-50 text-green-700 border-green-200' 
                                : 'bg-red-50 text-red-700 border-red-200'}`}
                        >
                            {isPassed ? 'PASSED ✅' : 'DISQUALIFIED ❌'}
                        </div>
                    )}
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default VotingControl;